import { getInput, setOutput } from '@actions/core';
import { readFileSync } from 'fs';
try {
    const path = getInput('path', { required: true });
    const filterOptional = getInput('filterOptional') === 'true';
    const inputFile = readFileSync(path);
    const entries = JSON.parse(inputFile.toString()).filter((entry) => !filterOptional || !entry.optional);
    const output = {
        component: entries.map(obj => obj.component),
        include: entries
    };
    setOutput('matrix', JSON.stringify(output));
}
catch (error) {
    if (error instanceof Error)
        setOutput('error', error.message);
}
